import openpyxl

wb = openpyxl.load_workbook('/app/spreadsheets/1_22-47_input.xlsx', data_only=True)
ws = wb['sheet1']

# Extract J
helper_j = []
for row in ws.iter_rows(min_row=2, max_row=ws.max_row, min_col=10, max_col=10, values_only=True):
    val = row[0]
    if val is not None and str(val).strip() != '':
        helper_j.append(str(val).strip())

print("Helper J:", helper_j)

# Extract A, B, C
data = []
seen = set()

for r in range(2, ws.max_row + 1):
    a = ws.cell(row=r, column=1).value
    b = ws.cell(row=r, column=2).value
    c = ws.cell(row=r, column=3).value

    if b is None or str(b).strip() == '':
        continue

    if str(a).strip().upper() == 'ITEM' or str(b).strip().upper() == 'NAME':
        continue

    dup_key = (str(b).strip(), str(c).strip())
    if dup_key in seen:
        continue
    seen.add(dup_key)

    data.append({
        'a': a,
        'b': str(b).strip(),
        'c': c,
        'orig_order': r
    })

print("Extracted data:")
for d in data:
    print(d)

# Sort
if helper_j:
    # We need to sort by J first
    # Names in J, in order of J
    # Then others in original order

    sorted_data = []
    # For each name in J, find matching rows in original order
    for j_name in helper_j:
        for d in data:
            if d['b'] == j_name:
                sorted_data.append(d)

    # For names not in J
    for d in data:
        if d['b'] not in helper_j:
            sorted_data.append(d)

else:
    # Sort A-Z by column B, keeping stable sort for original order
    sorted_data = sorted(data, key=lambda x: x['b'])

print("\nSorted data:")
for d in sorted_data:
    print(d)

